using System.ComponentModel;
using ModelContextProtocol.Server;

namespace HttpMcpServer.Tools;

[McpServerToolType]
public static class GreetingTools
{
    [McpServerTool, Description("Returns a personalized greeting message.")]
    public static string Greet(
        [Description("The name of the person to greet")] string name,
        [Description("Optional greeting style: formal or casual (default: casual)")] string style = "casual")
    {
        return style.Equals("formal", StringComparison.OrdinalIgnoreCase)
            ? $"Good day, {name}. How may I assist you?"
            : $"Hey {name}! ­¤æŗ What's up?";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace HttpMcpServer.Resources;

[McpServerResourceType]
public static class ConfigResource
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppConfig()
    {
        var config = new
        {
            AppName = "HttpMcpServer",
            Version = "1.0.0",
            Features = new { GreetingsEnabled = true, MaxRequestsPerMinute = 60 },
            SupportedStyles = new[] { "formal", "casual" }
        };

        return JsonSerializer.Serialize(config, JsonOptions);
    }

    [McpServerResource(
        UriTemplate = "config://environment/{envName}",
        Name = "Environment Configuration",
        MimeType = "application/json"),
     Description("Returns configuration for a specific environment (dev, staging, prod).")]
    public static string GetEnvironmentConfig(string envName)
    {
        var config = envName.ToLowerInvariant() switch
        {
            "dev" => new { Env = "dev", LogLevel = "Debug", CacheEnabled = false },
            "staging" => new { Env = "staging", LogLevel = "Information", CacheEnabled = true },
            "prod" => new { Env = "prod", LogLevel = "Warning", CacheEnabled = true },
            _ => new { Env = envName, LogLevel = "Information", CacheEnabled = false }
        };

        return JsonSerializer.Serialize(config, JsonOptions);
    }
}

